/* Style for Age Verification Pop-up */
#age-verification-popup {
  display: none;
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: rgba(0, 0, 0, 0.8);
  z-index: 9999;
}
.popup-content {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  background-color: #fff;
  padding: 20px;
  text-align: center;
}
#verify-button {
  background-color: #007acc;
  color: #fff;
  padding: 10px 20px;
  border: none;
  cursor: pointer;
}

